from flask import Flask, session, url_for, redirect, request, render_template
import requests
import json

app = Flask(__name__)
app.secret_key = 'your_secret_key_here'

# OpenID Connect settings (replace with your provider's)
AUTH_URL = 'https://example.com/authorize'
TOKEN_URL = 'https://example.com/token'
ID_TOKEN_VERIFICATION_ENDPOINT = 'https://example.com/.well-known/jwk_sets'
CLIENT_ID = 'your_client_id_here'
CLIENT_SECRET = 'your_client_secret_here'
REDIRECT_URI = url_for('callback', _external=True)

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login')
def login():
    auth_params = {
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'response_type': 'code',
        'scope': 'openid profile email'
    }
    return redirect(f'{AUTH_URL}?{requests.compat.urlencode(auth_params)}')

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if code:
        token_data = get_token(code)
        id_token = decode_id_token(token_data['id_token'])
        session['user'] = {
            'username': id_token['email'],
            'name': id_token['name'],
            'email': id_token['email']
        }
        return redirect(url_for('protected'))
    else:
        return render_template('error.html', error='No code provided')

def get_token(code):
    token_data = requests.post(
        TOKEN_URL,
        data={
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': REDIRECT_URI,
            'client_id': CLIENT_ID,
            'client_secret': CLIENT_SECRET
        }
    ).json()
    return token_data

def decode_id_token(id_token):
    key_url = f'{ID_TOKEN_VERIFICATION_ENDPOINT}'
    response = requests.get(key_url).json()
    public_key = None
    for jwk in response['keys']:
        if jwk['kid'] == 'your_client_jwk_kid_here':
            public_key = {
                'kty': jwk['kty'],
                'n': jwk['n'],
                'e': jwk['e']
            }
            break
    assert public_key, f"No JWK found for client ID '{CLIENT_ID}'"
    payload = jwt.decode(id_token, public_key, algorithms='RS256')
    return payload

@app.route('/protected')
def protected():
    if 'user' in session:
        return render_template('protected.html', user=session['user'])
    else:
        return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=True)